begin

    process(pixel_row, pixel_col, icon_x, icon_y)
        variable px : integer;
        variable py : integer;
        variable ix : integer;
        variable iy : integer;
        variable sx : integer;
        variable sy : integer;
        variable color_idx : std_logic_vector(3 downto 0);
    begin
        px := to_integer(unsigned(pixel_col));
        py := to_integer(unsigned(pixel_row));
        ix := to_integer(unsigned(icon_x));
        iy := to_integer(unsigned(icon_y));

        red     <= "0000";
        green   <= "0000";
        blue    <= "0000";
        visible <= '0';

        if px >= ix and px < ix + SPRITE_W and
           py >= iy and py < iy + SPRITE_H then

            sx := px - ix;
            sy := py - iy;

            color_idx := SPRITE_SPRITE(sy)(sx);

            if color_idx /= "0000" then
                visible <= '1';

                case color_idx is
                    when "0001" => -- black
                        red   <= "0000";
                        green <= "0000";
                        blue  <= "0000";

                    when "0010" => -- red
                        red   <= "1111";
                        green <= "0000";
                        blue  <= "0000";

                    when "0011" => -- sprite green
                        red   <= "0001";
                        green <= "1000";
                        blue  <= "0101";

                    when "0100" => -- yellow
                        red   <= "1111";
                        green <= "1111";
                        blue  <= "0000";

                    when "0101" => -- white
                        red   <= "1111";
                        green <= "1111";
                        blue  <= "1111";

                    when "0110" => -- light grey
                        red   <= "1011";
                        green <= "1011";
                        blue  <= "1011";

                    when "0111" => -- medium grey
                        red   <= "0111";
                        green <= "0111";
                        blue  <= "0111";

                    when others =>
                        red   <= "0000";
                        green <= "0000";
                        blue  <= "0000";
                end case;
            end if;
        end if;
    end process;

end Behavioral;